time<pre><code>函数原型 time_t time(time_t *t);
所属头文件：&lt;time.h&gt;
参数 t - NULL
返回值:成功返回long int型的日历时间 秒数，失败返回-1
</code></pre> 举例time<pre><code>#include &lt;stdio.h&gt;
#include &lt;time.h&gt;
int main()
{
time_t t = time(NULL);
printf("%ld\n",t);
return 0;
}
</code></pre>

localtime<pre><code>功能：将time指向的日历时间转换为本地时间
原型 struct tm *localtime(const time_t *timep);
所属头文件：&lt;time.h&gt;
参数 timep:指向待转化日历时间
返回值：
成功：返回以struct tm形式存储的本地时间，失败返回NULL
struct tm {
int tm_sec;    /* Seconds (0-60) */
int tm_min;    /* Minutes (0-59) */
int tm_hour;   /* Hours (0-23) */
int tm_mday;   /* Day of the month (1-31) */
int tm_mon;    /*Month(0-11)*/ +1
int tm_year;   /*Year-1900*/ +1900
int tm_wday;   /* Day of the week (0-6, Sunday = 0) */
int tm_yday;   /* Day in the year (0-365, 1 Jan = 0) */
int tm_isdst;  /*Daylight saving time */
};
</code></pre> 举例localtime<pre><code>#include &lt;stdio.h&gt;
#include &lt;time.h&gt;
int main()
{
time_t t = time(NULL);
printf("%ld\n",t);
struct tm *p = localtime(&amp;t);
printf("%d-%d-%d %d:%d:%d\n",p-&gt;tm_year+1900,p-&gt;tm_mon+1,p-&gt;tm_mday,p-&gt;tm_hour,p-&gt;tm_min,p-&gt;tm_sec);
return 0;
}
</code></pre>

gmtime<pre><code>功能 将参数timep所指定的日历时间转换为标准时间
原型：
struct tm *gmtime(const time_t *timep);
所属头文件&lt;time.h&gt;
参数：timep待转化的日历时间
返回值 成功返回世界标准时间，以struct tm形式存储
struct tm {
int tm_sec;    /* Seconds (0-60) */
int tm_min;    /* Minutes (0-59) */
int tm_hour;   /*Hours(0-23)*/+8
int tm_mday;   /* Day of the month (1-31) */
int tm_mon;    /*Month(0-11)*/+1
int tm_year;   /*Year-1900*/ +1900
int tm_wday;   /* Day of the week (0-6, Sunday = 0) */
int tm_yday;   /* Day in the year (0-365, 1 Jan = 0) */
int tm_isdst;  /*Daylight saving time */
};
</code></pre> 举例gmtime<pre><code>#include &lt;stdio.h&gt;
#include &lt;time.h&gt;
int main()
{
time_t t = time(NULL);
printf("%ld\n",t);
struct tm *p = gmtime(&amp;t);
printf("%d-%d-%d %d:%d:%d\n",p-&gt;tm_year+1900,p-&gt;tm_mon+1,p-&gt;tm_mday,p-&gt;tm_hour+8,p-&gt;tm_min,p-&gt;tm_sec);
return 0;
}
</code></pre>

asctime<pre><code>原型 char *asctime(const struct tm *tm);
所属头文件： &lt;time.h&gt;
参数：待转化的tm格式的时间
返回值：字符串显示的时间
</code></pre> 举例asctime<pre><code>#include &lt;stdio.h&gt;
#include &lt;time.h&gt;
int main()
{
time_t t = time(NULL);
printf("%ld\n",t);
struct tm *p = localtime(&amp;t);//或 struct tm *p = gmtime(&amp;t); 使用gmtime 显示时间与北京时间少8小时
char *z = asctime(p);
printf("%s\n",z);
return 0;
}
</code></pre>

